evals.prompt:
This Vespa schema has several bugs. Find and fix ALL of them. Write the corrected schema to schemas/products.sd

Here is the broken schema:

schema products {
    document product {
        field title type string {
            indexing: summary | index
        }
        field category type string {
            indexing: attribute
            match: exact
        }
        field embedding type tensor<float>(d[384]) {
            indexing: summary | attribute
            index {
                hnsw {
                    max-links-per-node: 16
                }
            }
        }
    }
    rank-profile semantic {
        inputs {
            query(q) tensor<float>(x[384])
        }
        first-phase {
            expression: closeness(field, embedding)
        }
    }
    rank-profile text_search {
        first-phase {
            expression: bm25(title)
        }
    }
}
